function createBaseRuntimeRpc(): RuntimeRpc {
  return { request: undefined, response: undefined };
}

export const RuntimeRpc: MessageFns<RuntimeRpc> = {
  encode(message: RuntimeRpc, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.request !== undefined) {
      RuntimeRpcRequest.encode(message.request, writer.uint32(10).fork()).join();
    }
    if (message.response !== undefined) {
      RuntimeRpcResponse.encode(message.response, writer.uint32(18).fork()).join();
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): RuntimeRpc {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseRuntimeRpc();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 10) {
            break;
          }

          message.request = RuntimeRpcRequest.decode(reader, reader.uint32());
          continue;
        }
        case 2: {
          if (tag !== 18) {
            break;
          }

          message.response = RuntimeRpcResponse.decode(reader, reader.uint32());
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): RuntimeRpc {
    return {
      request: isSet(object.request) ? RuntimeRpcRequest.fromJSON(object.request) : undefined,
      response: isSet(object.response) ? RuntimeRpcResponse.fromJSON(object.response) : undefined,
    };
  },

  toJSON(message: RuntimeRpc): unknown {
    const obj: any = {};
    if (message.request !== undefined) {
      obj.request = RuntimeRpcRequest.toJSON(message.request);
    }
    if (message.response !== undefined) {
      obj.response = RuntimeRpcResponse.toJSON(message.response);
    }
    return obj;
  },

  create(base?: DeepPartial<RuntimeRpc>): RuntimeRpc {
    return RuntimeRpc.fromPartial(base ?? {});
  },
  fromPartial(object: DeepPartial<RuntimeRpc>): RuntimeRpc {
    const message = createBaseRuntimeRpc();
    message.request = (object.request !== undefined && object.request !== null)
      ? RuntimeRpcRequest.fromPartial(object.request)
      : undefined;
    message.response = (object.response !== undefined && object.response !== null)
      ? RuntimeRpcResponse.fromPartial(object.response)
      : undefined;
    return message;
  },
};

type Builtin = Date | Function | Uint8Array | string | number | boolean | undefined;

type DeepPartial<T> = T extends Builtin ? T
  : T extends globalThis.Array<infer U> ? globalThis.Array<DeepPartial<U>>
  : T extends ReadonlyArray<infer U> ? ReadonlyArray<DeepPartial<U>>
  : T extends {} ? { [K in keyof T]?: DeepPartial<T[K]> }
  : Partial<T>;

function isObject(value: any): boolean {
  return typeof value === "object" && value !== null;
}

function isSet(value: any): boolean {
  return value !== null && value !== undefined;
}

interface MessageFns<T> {
  encode(message: T, writer?: BinaryWriter): BinaryWriter;
  decode(input: BinaryReader | Uint8Array, length?: number): T;
  fromJSON(object: any): T;
  toJSON(message: T): unknown;
  create(base?: DeepPartial<T>): T;
  fromPartial(object: DeepPartial<T>): T;
}
